  "inlineSchema": "// This is your Prisma schema file,\n// learn more about it in the docs: https://pris.ly/d/prisma-schema\n\ngenerator client {\n  provider = \"prisma-client-js\"\n  output   = \"../generated/prisma\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// User management with NextAuth.js support\nmodel User {\n  id        String   @id @default(cuid())\n  email     String   @unique\n  username  String   @unique\n  name      String?\n  avatar    String?\n  githubId  String?  @unique\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // NextAuth.js fields\n  image         String?\n  emailVerified DateTime?\n\n  // Owned projects\n  ownedProjects Project[]\n\n  // Project memberships\n  memberships ProjectMember[]\n\n  // AI chat sessions\n  aiSessions AiChatSession[]\n\n  // File activities\n  fileActivities FileActivity[]\n\n  // Collaboration sessions\n  sessionParticipations SessionParticipant[]\n\n  // NextAuth.js relations\n  accounts Account[]\n  sessions Session[]\n\n  @@map(\"users\")\n}\n\n// NextAuth.js Account model\nmodel Account {\n  id                String  @id @default(cuid())\n  userId            String\n  type              String\n  provider          String\n  providerAccountId String\n  refresh_token     String? @db.Text\n  access_token      String? @db.Text\n  expires_at        Int?\n  token_type        String?\n  scope             String?\n  id_token          String? @db.Text\n  session_state     String?\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@unique([provider, providerAccountId])\n  @@map(\"accounts\")\n}\n\n// NextAuth.js Session model\nmodel Session {\n  id           String   @id @default(cuid())\n  sessionToken String   @unique\n  userId       String\n  expires      DateTime\n  user         User     @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@map(\"sessions\")\n}\n\n// NextAuth.js VerificationToken model\nmodel VerificationToken {\n  identifier String\n  token      String   @unique\n  expires    DateTime\n\n  @@unique([identifier, token])\n  @@map(\"verificationtokens\")\n}\n\n// Project management\nmodel Project {\n  id            String            @id @default(cuid())\n  name          String\n  description   String?\n  visibility    ProjectVisibility @default(PRIVATE)\n  repositoryUrl String?\n\n  // Owner\n  ownerId String\n  owner   User   @relation(fields: [ownerId], references: [id], onDelete: Cascade)\n\n  // Timestamps\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // Project structure\n  files ProjectFile[]\n\n  // Collaboration\n  members  ProjectMember[]\n  sessions CollaborationSession[]\n\n  // AI interactions\n  aiSessions AiChatSession[]\n\n  // Git integration\n  gitRepository GitRepository?\n\n  @@map(\"projects\")\n}\n\nenum ProjectVisibility {\n  PRIVATE\n  PUBLIC\n  TEAM\n}\n\n// Project team management\nmodel ProjectMember {\n  id   String      @id @default(cuid())\n  role ProjectRole @default(DEVELOPER)\n\n  // Relations\n  userId String\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  projectId String\n  project   Project @relation(fields: [projectId], references: [id], onDelete: Cascade)\n\n  // Timestamps\n  joinedAt DateTime @default(now())\n\n  @@unique([userId, projectId])\n  @@map(\"project_members\")\n}\n\nenum ProjectRole {\n  OWNER\n  ADMIN\n  DEVELOPER\n  VIEWER\n}\n\n// File system\nmodel ProjectFile {\n  id       String   @id @default(cuid())\n  path     String // Full path within project\n  name     String // File name\n  type     FileType @default(FILE)\n  content  String? // File content (for text files)\n  size     Int      @default(0)\n  mimeType String?\n\n  // Project relation\n  projectId String\n  project   Project @relation(fields: [projectId], references: [id], onDelete: Cascade)\n\n  // Timestamps\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // File activities (edits, views, etc.)\n  activities FileActivity[]\n\n  @@unique([projectId, path])\n  @@map(\"project_files\")\n}\n\nenum FileType {\n  FILE\n  DIRECTORY\n}\n\n// File activity tracking\nmodel FileActivity {\n  id      String     @id @default(cuid())\n  action  FileAction\n  changes Json? // Delta/diff information\n\n  // Relations\n  fileId String\n  file   ProjectFile @relation(fields: [fileId], references: [id], onDelete: Cascade)\n\n  userId String\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  // Timestamps\n  createdAt DateTime @default(now())\n\n  @@map(\"file_activities\")\n}\n\nenum FileAction {\n  CREATE\n  UPDATE\n  DELETE\n  RENAME\n  MOVE\n  VIEW\n}\n\n// Real-time collaboration sessions\nmodel CollaborationSession {\n  id       String  @id @default(cuid())\n  name     String // Session name/description\n  isActive Boolean @default(true)\n\n  // Project relation\n  projectId String\n  project   Project @relation(fields: [projectId], references: [id], onDelete: Cascade)\n\n  // Session participants\n  participants SessionParticipant[]\n\n  // Timestamps\n  createdAt DateTime  @default(now())\n  updatedAt DateTime  @updatedAt\n  endedAt   DateTime?\n\n  @@map(\"collaboration_sessions\")\n}\n\n// Session participants for presence tracking\nmodel SessionParticipant {\n  id String @id @default(cuid())\n\n  // Relations\n  sessionId String\n  session   CollaborationSession @relation(fields: [sessionId], references: [id], onDelete: Cascade)\n\n  userId String\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  // Participant state\n  cursor   Json? // Cursor position, selections\n  isActive Boolean @default(true)\n\n  // Timestamps\n  joinedAt DateTime  @default(now())\n  leftAt   DateTime?\n\n  @@unique([sessionId, userId])\n  @@map(\"session_participants\")\n}\n\n// AI Chat and assistance\nmodel AiChatSession {\n  id      String    @id @default(cuid())\n  title   String?\n  context AiContext @default(GENERAL)\n\n  // Relations\n  userId String\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  projectId String? // Optional project context\n  project   Project? @relation(fields: [projectId], references: [id], onDelete: SetNull)\n\n  // Messages in this session\n  messages AiMessage[]\n\n  // Timestamps\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@map(\"ai_chat_sessions\")\n}\n\nenum AiContext {\n  GENERAL\n  CODE_REVIEW\n  DEBUGGING\n  ARCHITECTURE\n  DOCUMENTATION\n}\n\n// AI chat messages\nmodel AiMessage {\n  id       String      @id @default(cuid())\n  role     MessageRole\n  content  String\n  metadata Json? // Token usage, model info, etc.\n\n  // Session relation\n  sessionId String\n  session   AiChatSession @relation(fields: [sessionId], references: [id], onDelete: Cascade)\n\n  // Timestamps\n  createdAt DateTime @default(now())\n\n  @@map(\"ai_messages\")\n}\n\nenum MessageRole {\n  USER\n  ASSISTANT\n  SYSTEM\n}\n\n// Git integration metadata (optional)\nmodel GitRepository {\n  id         String     @id @default(cuid())\n  url        String     @unique\n  branch     String     @default(\"main\")\n  lastSync   DateTime?\n  syncStatus SyncStatus @default(PENDING)\n\n  // Project relation\n  projectId String  @unique\n  project   Project @relation(fields: [projectId], references: [id], onDelete: Cascade)\n\n  // Commits tracking\n  commits GitCommit[]\n\n  // Timestamps\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@map(\"git_repositories\")\n}\n\nenum SyncStatus {\n  PENDING\n  SYNCING\n  SYNCED\n  ERROR\n}\n\n// Git commit history\nmodel GitCommit {\n  id          String @id @default(cuid())\n  hash        String @unique\n  message     String\n  author      String\n  authorEmail String\n\n  // Repository relation\n  repoId     String\n  repository GitRepository @relation(fields: [repoId], references: [id], onDelete: Cascade)\n\n  // Timestamps\n  committedAt DateTime\n  createdAt   DateTime @default(now())\n\n  @@map(\"git_commits\")\n}\n",
